INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3a035a5b-ba8a-4883-8c19-7e465b326bbb', '049a4723-eaa3-460a-b738-288f24ae391a', 'JSX is a syntax extension; React is a JavaScript library. They can be used independently.', TRUE, 0);
