INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ca806998-dc6c-4e2a-ad2c-35e4618e9d8b', '07827e07-151f-48b6-bca7-baee116bb678', 'It is very slow and causes bugs because React treats each render as a new, different component, resetting its state.', TRUE, 0);
