INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('13e1863f-b5d1-4c70-93fe-3b46580c6708', 'e82a0e87-0428-48d6-8c98-32d13f907c86', 'It must complete in under 16 ms to not block the browser.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('fdefd12b-2579-4377-babb-ad0985d30a78', '903cd62c-a29c-4732-b8b0-6ad9138685a7', 'It schedules a new render; the state value does not change in the current render.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5ce889b8-e651-4611-a921-6a0e329efc9c', '903cd62c-a29c-4732-b8b0-6ad9138685a7', 'It immediately mutates the state variable in place.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d5874bec-3ef3-451d-82ee-4fac63e9e594', '903cd62c-a29c-4732-b8b0-6ad9138685a7', 'It synchronously re-runs the component function within the same call stack.', FALSE, 2);
