INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f5c4a199-0396-4df5-b6c8-b0c1da64183c', '65294e0a-a15f-47fe-8650-7b850c5a46a4', '3', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3841a890-d7c1-40d7-b142-d231c0b01c8d', '65294e0a-a15f-47fe-8650-7b850c5a46a4', '0', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('35ea3182-f43c-46da-9b65-c07fa8645305', '65294e0a-a15f-47fe-8650-7b850c5a46a4', 'The result is undefined because multiple setters in one handler are not allowed.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('aacaf21f-d904-4d5c-b05a-c8a7d6cdf004', '4f5c9039-c6aa-4565-ae64-f4747150025f', '0, because the alert captured the snapshot value of `number` at the time of the click.', TRUE, 0);
