INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d8127552-8176-4ade-8584-c17caeccf434', '126615d2-dd59-4a26-928f-3d9456ee8912', 'The latest state value at the time the timeout fires.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('30b2f5d1-864f-46de-800e-0bc109d7ecce', '126615d2-dd59-4a26-928f-3d9456ee8912', '0, because `number` resets between renders.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0d0cdeab-ad44-4330-85cf-b687abfc97ac', '95b6ca7b-f5d8-4db5-98e1-e725037d47a4', 'React waits until all code in the event handler has run before processing state updates and re-rendering.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('52b837a3-7508-49ae-8e18-d58ddf3ef36a', '95b6ca7b-f5d8-4db5-98e1-e725037d47a4', 'React groups all state variables into a single object to reduce memory usage.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('38758015-928f-4e74-8d97-0da59c3188c2', '95b6ca7b-f5d8-4db5-98e1-e725037d47a4', 'React delays all state updates by 100 ms to improve performance.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2f414bb6-0834-40c4-949a-d58418f0fce5', '95b6ca7b-f5d8-4db5-98e1-e725037d47a4', 'React processes each state update in a separate Web Worker thread.', FALSE, 3);
