INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('596021fb-5059-468e-90a3-85804c830b5f', '38d4c93d-2701-4752-9cc7-34ebdabcd3e7', 'Call `setPerson` with only `{ firstName: e.target.value }` — React merges it automatically.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('52e4eb87-a933-4aa9-a551-b4e011e46026', '38d4c93d-2701-4752-9cc7-34ebdabcd3e7', 'Maintain separate state variables for each field and update the relevant one.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('694f68a0-4ea5-47e3-800b-6b8cc53f1b0a', '224fe932-ac9d-4a83-a921-38febef455a0', 'It is shallow — it only copies one level deep, so nested objects still share the same reference.', TRUE, 0);
