INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2c2c8fbc-eb59-4041-8bd9-0220b93283ab', '6eb5446f-8acd-4188-a03f-bf63cd7a9865', 'Both are identical; one is just an older alias for the other.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c71c06fc-409d-468a-adb6-cbad2a63dfd8', '6eb5446f-8acd-4188-a03f-bf63cd7a9865', '`slice` works on strings; `splice` works on arrays.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6ac72062-aa67-4015-ba01-dd621a8b06c2', '0faa9b4a-c232-421d-9492-1b8ce4473f4f', 'Yes — the spread is shallow, so nested objects are still shared references; modifying them mutates the original state.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1082957d-0b96-4209-9494-9858d3bae1ab', '0faa9b4a-c232-421d-9492-1b8ce4473f4f', 'No — spreading always performs a deep clone, so the original array is unaffected.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e58233fc-2bd5-49ad-9c67-9ee8896fd415', '0faa9b4a-c232-421d-9492-1b8ce4473f4f', 'No — React''s state system automatically prevents mutations on copied arrays.', FALSE, 2);
