INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c9f742a0-50a3-42cf-923f-6e5869b6a472', '4d81dfec-1c51-423d-9939-a09f35696334', 'The old value — `set` functions do not change state in the currently executing code.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8757592a-106d-41a0-b5b7-6e3a425ec17e', '4d81dfec-1c51-423d-9939-a09f35696334', 'The new value `''Robin''`, because React applies updates synchronously.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1133c2ab-0409-477c-aa10-15765db70cf0', '4d81dfec-1c51-423d-9939-a09f35696334', '`undefined`, because the state has been invalidated but not yet re-computed.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8ad3e88c-3e8a-4af3-b5c8-d8cee0913688', '4d81dfec-1c51-423d-9939-a09f35696334', 'An error is thrown if you read state after calling its setter in the same handler.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('23c815cd-adb1-462f-afcc-348f5cd9bf25', 'b319b639-f851-4f67-b7de-b1cd7c86fe3b', 'When the new state is identical to the current state according to `Object.is`.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('cc71640d-8b0b-493f-b0ef-b302ab5c7136', 'b319b639-f851-4f67-b7de-b1cd7c86fe3b', 'When the component is not currently visible in the viewport.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6d15ef46-7955-4830-9685-beb0df75c1f0', 'b319b639-f851-4f67-b7de-b1cd7c86fe3b', 'When `shouldComponentUpdate` returns `false`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('870120aa-250d-40c6-9d95-4fb26a5267a9', 'b319b639-f851-4f67-b7de-b1cd7c86fe3b', 'When the component has no children.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2410e42d-3abd-452c-97f4-952b9e8511dd', 'f39ccb42-7ade-4299-aab7-31674acebf47', 'Wrap the function in an arrow function: `useState(() => someFunction)`.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('260382a1-61ce-48d0-b88c-09d7e9ea93e1', 'f39ccb42-7ade-4299-aab7-31674acebf47', 'Pass the function directly: `useState(someFunction)` — React detects it is a non-initializer.', FALSE, 1);
